// Variables globales
int n, P;
vector<int> peso, alegria;
int mejorAlegria;
vector<bool> mejorSel, selActual;

double estimacion(int i, int pesoAcum, int alegAcum) {
    double est = alegAcum;
    int pAcum = pesoAcum;
    for (int j = i; j < n; j++) {
        if (pAcum + peso[j] <= P) {
            pAcum += peso[j];
            est += alegria[j];
        } else {
            int hueco = P - pAcum;
            est += (double)alegria[j] * hueco / peso[j];
            break;
        }
    }
    return est;
}

void bt(int i, int pesoAcum, int alegAcum) {
    if (estimacion(i, pesoAcum, alegAcum) <= mejorAlegria) return;
    if (i == n) {
        mejorAlegria = alegAcum;
        mejorSel = selActual;
        return;
    }
    // Incluir regalo i
    if (pesoAcum + peso[i] <= P) {
        selActual[i] = true;
        bt(i+1, pesoAcum + peso[i], alegAcum + alegria[i]);
        selActual[i] = false;
    }
    // No incluir regalo i
    bt(i+1, pesoAcum, alegAcum);
}
